from typing import Any, Dict, List
import logging

logger = logging.getLogger(__name__)

class DataValidator:
    def __init__(self, schema: Dict[str, type]):
        self.schema = schema

    def validate(self, record: Dict[str, Any]) -> List[str]:
        errors = []
        for field, expected_type in self.schema.items():
            if field not in record:
                errors.append(f'Missing required field: {field}')
            elif not isinstance(record[field], expected_type):
                errors.append(f'{field}: expected {expected_type.__name__}, got {type(record[field]).__name__}')
        return errors

import re
from datetime import datetime
from typing import Optional
import logging

logger = logging.getLogger(__name__)

CRON_PATTERN = re.compile(r'^(\*|\d+)\s+(\*|\d+)\s+(\*|\d+)\s+(\*|\d+)\s+(\*|\d+)$')

def parse_cron(expression: str) -> Optional[dict]:
    match = CRON_PATTERN.match(expression.strip())
    if not match:
        raise ValueError(f'Invalid cron expression: {expression}')
    fields = ['minute', 'hour', 'day', 'month', 'weekday']
    return {fields[i]: match.group(i + 1) for i in range(5)}

def should_run(cron_expr: str, now: Optional[datetime] = None) -> bool:
    now = now or datetime.now()
    schedule = parse_cron(cron_expr)
    if schedule['minute'] != '*' and int(schedule['minute']) != now.minute:
        return False
    if schedule['hour'] != '*' and int(schedule['hour']) != now.hour:
        return False
    return True

