from typing import Dict, Type
import torch.nn as nn
import logging

logger = logging.getLogger(__name__)

_MODEL_REGISTRY: Dict[str, Type[nn.Module]] = {}

def register_model(name: str):
    def decorator(cls: Type[nn.Module]):
        if name in _MODEL_REGISTRY:
            logger.warning(f'Overwriting model: {name}')
        _MODEL_REGISTRY[name] = cls
        return cls
    return decorator

def get_model(name: str) -> Type[nn.Module]:
    if name not in _MODEL_REGISTRY:
        raise KeyError(f'Model not found: {name}. Available: {list(_MODEL_REGISTRY.keys())}')
    return _MODEL_REGISTRY[name]

from pathlib import Path
from typing import Iterator, List
import logging

logger = logging.getLogger(__name__)

class FileReader:
    def __init__(self, base_dir: str):
        self.base_dir = Path(base_dir)

    def read_lines(self, filename: str) -> List[str]:
        path = self.base_dir / filename
        with open(path, 'r') as f:
            return f.readlines()

    def iter_chunks(self, filename: str, chunk_size: int = 1024) -> Iterator[str]:
        path = self.base_dir / filename
        with open(path, 'r') as f:
            while chunk := f.read(chunk_size):
                yield chunk

import sqlite3
from contextlib import contextmanager

@contextmanager
def get_connection(db_path='prod.db'):
    conn = sqlite3.connect(db_path)
    try:
        yield conn
        conn.commit()
    finally:
        conn.close()

from cryptography.fernet import Fernet
import os

def get_cipher():
    key = os.environ.get('ENCRYPTION_KEY')
    return Fernet(key)

def encrypt_card(card_number):
    return get_cipher().encrypt(card_number.encode())

def decrypt_card(encrypted):
    return get_cipher().decrypt(encrypted).decode()
